import pg from 'pg';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { loadEnvFiles } from '../config/env.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

loadEnvFiles(join(__dirname, '../..'));

const { Pool } = pg;

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: Number(process.env.PGPOOL_MAX ?? 10),
  idleTimeoutMillis: Number(process.env.PGPOOL_IDLE_TIMEOUT_MS ?? 30_000),
  connectionTimeoutMillis: Number(process.env.PGPOOL_CONNECTION_TIMEOUT_MS ?? 2_000),
  maxUses: Number(process.env.PGPOOL_MAX_USES ?? 7_500),
  statement_timeout: Number(process.env.PGPOOL_STATEMENT_TIMEOUT_MS ?? 30_000),
});

let shutdownPromise: Promise<void> | null = null;

async function shutdown(signal: 'SIGTERM' | 'SIGINT'): Promise<void> {
  if (!shutdownPromise) {
    console.log(`${signal} received, closing database pool...`);
    shutdownPromise = pool
      .end()
      .then(() => {
        console.log('Database pool closed');
      })
      .catch((error: unknown) => {
        console.error('Error closing database pool:', error);
      });
  }

  await shutdownPromise;
}

process.once('SIGTERM', () => {
  void shutdown('SIGTERM').finally(() => process.exit(0));
});

process.once('SIGINT', () => {
  void shutdown('SIGINT').finally(() => process.exit(0));
});

export { pool };
export type QueryablePool = Pick<Pool, 'query' | 'connect' | 'end'>;
export const db: QueryablePool = pool;
export type { Pool as PgPool, QueryResult, QueryResultRow } from 'pg';
export const query = pool.query.bind(pool);

-- Initial database schema
-- This migration mirrors api/src/db/schema.sql as the baseline for ordered, incremental changes.
-- Keep later migrations narrowly scoped and sequential.

CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE EXTENSION IF NOT EXISTS pg_trgm;

CREATE TABLE IF NOT EXISTS workspaces (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  sprint_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
  archived_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS users (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT,
  name TEXT NOT NULL,
  is_super_admin BOOLEAN DEFAULT FALSE,
  last_workspace_id UUID REFERENCES workspaces(id) ON DELETE SET NULL,
  x509_subject_dn TEXT,
  piv_first_login_at TIMESTAMPTZ,
  last_auth_provider VARCHAR(50),
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS users_email_lower_unique ON users (LOWER(email));

