CREATE OR REPLACE FUNCTION assign_workspace_ticket_number()
RETURNS TRIGGER AS $$
DECLARE
  next_ticket INTEGER;
BEGIN
  IF NEW.ticket_number IS NOT NULL OR NEW.document_type NOT IN ('issue', 'project', 'program', 'wiki', 'person', 'sprint') THEN
    RETURN NEW;
  END IF;

  IF NEW.document_type = 'wiki' THEN
    RETURN NEW;
  END IF;

  IF NEW.document_type = 'person' THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(MAX(ticket_number), 0) + 1
    INTO next_ticket
  FROM documents
  WHERE workspace_id = NEW.workspace_id
    AND ticket_number IS NOT NULL;

  NEW.ticket_number := next_ticket;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS assign_workspace_ticket_number_trigger ON documents;
CREATE TRIGGER assign_workspace_ticket_number_trigger
BEFORE INSERT ON documents
FOR EACH ROW
EXECUTE FUNCTION assign_workspace_ticket_number();

CREATE OR REPLACE FUNCTION bump_workspace_document_update_timestamp()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

