  );

  if (!existingDoc.rows[0]) {
    await pool.query(
      `INSERT INTO documents (workspace_id, document_type, title, parent_id)
       VALUES ($1, 'wiki', $2, $3)`,
      [workspaceId, doc.title, doc.parentId]
    );
    nestedDocsCreated++;
  }
}

