      [workspaceId, doc.title, JSON.stringify(contentJson), i + 1]
    );
    standaloneDocsCreated++;
  }
}

if (standaloneDocsCreated > 0) {
  console.log(`✅ Created ${standaloneDocsCreated} standalone wiki documents`);
}

