#!/usr/bin/env npx ts-node
import { Pool } from 'pg';
import { loadProductionSecrets } from '../../config/ssm.js';
import { loadEnvFiles } from '../../config/env.js';
import { getDatabaseSslConfig } from '../ssl.js';

loadEnvFiles(new URL('../../..', import.meta.url).pathname);

async function main() {
  await loadProductionSecrets();

  const databaseUrl = process.env.DATABASE_URL;
  if (!databaseUrl) {
    console.error('ERROR: DATABASE_URL environment variable is not set');
    process.exit(1);
  }

  const pool = new Pool({ connectionString: databaseUrl, ssl: getDatabaseSslConfig() });

  try {
    const tables = await pool.query(`
      SELECT table_name
      FROM information_schema.tables
      WHERE table_schema = 'public'
      ORDER BY table_name
    `);

    for (const row of tables.rows) {
      console.log(`TABLE ${row.table_name}`);
      const columns = await pool.query(
        `SELECT column_name, data_type, is_nullable
         FROM information_schema.columns
         WHERE table_schema = 'public' AND table_name = $1
         ORDER BY ordinal_position`,
        [row.table_name]
      );
      for (const col of columns.rows) {
        console.log(`  ${col.column_name}\t${col.data_type}\t${col.is_nullable}`);
      }
    }
  } finally {
    await pool.end();
  }
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});

