     2	-- This protects against infinite loops in recursive CTE queries
     3	
     4	-- Step 1: Add simple CHECK constraint for self-reference
     5	DO $$
     6	BEGIN
     7	  IF NOT EXISTS (
     8	    SELECT 1
     9	    FROM pg_constraint
    10	    WHERE conname = 'documents_no_self_parent'
    11	  ) THEN
    12	    ALTER TABLE documents
    13	    ADD CONSTRAINT documents_no_self_parent
    14	    CHECK (id != parent_id);
    15	  END IF;
    16	END
    17	$$;
    18	
    19	-- Step 2: Create function to detect circular references by traversing ancestors
    20	CREATE OR REPLACE FUNCTION prevent_circular_parent()
    21	RETURNS TRIGGER AS $$
    22	DECLARE
    23	  current_parent UUID;
    24	  depth INT := 0;
    25	  max_depth INT := 100;
    26	BEGIN
    27	  -- Skip check if parent_id is NULL or unchanged
    28	  IF NEW.parent_id IS NULL THEN
    29	    RETURN NEW;
    30	  END IF;
    31	
    32	  -- For updates, skip if parent_id hasn't changed
    33	  IF TG_OP = 'UPDATE' AND OLD.parent_id IS NOT DISTINCT FROM NEW.parent_id THEN
    34	    RETURN NEW;
    35	  END IF;
    36	
    37	  -- Traverse up the tree to check for cycles
    38	  current_parent := NEW.parent_id;
    39	
    40	  WHILE current_parent IS NOT NULL AND depth < max_depth LOOP
    41	    -- If we find the new document's ID in ancestors, it's a cycle
    42	    IF current_parent = NEW.id THEN
    43	      RAISE EXCEPTION 'Circular reference detected: document % cannot be a descendant of itself', NEW.id;
    44	    END IF;
    45	
    46	    -- Move up to the parent's parent
    47	    SELECT parent_id INTO current_parent
    48	    FROM documents
    49	    WHERE id = current_parent;
    50	
    51	    depth := depth + 1;
    52	  END LOOP;
    53	
    54	  -- If we hit max depth, something is wrong
    55	  IF depth >= max_depth THEN
    56	    RAISE EXCEPTION 'Maximum nesting depth (%) exceeded while checking for circular reference', max_depth;
    57	  END IF;
    58	
    59	  RETURN NEW;
    60	END;
    61	$$ LANGUAGE plpgsql;
    62	
    63	-- Step 3: Create trigger to run the function
    64	DROP TRIGGER IF EXISTS prevent_circular_parent_trigger ON documents;
    65	
    66	CREATE TRIGGER prevent_circular_parent_trigger
    67	BEFORE INSERT OR UPDATE OF parent_id ON documents
    68	FOR EACH ROW
    69	EXECUTE FUNCTION prevent_circular_parent();
