   202	-- Relationship type enum for document associations
   203	DO $$
   204	BEGIN
   205	  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'relationship_type') THEN
   206	    CREATE TYPE relationship_type AS ENUM ('parent', 'project', 'sprint', 'program');
   207	  END IF;
   208	END
   209	$$;
