   211	-- Document associations junction table (replaces direct relationship columns)
   212	CREATE TABLE IF NOT EXISTS document_associations (
   213	  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
   214	  document_id UUID NOT NULL REFERENCES documents(id) ON DELETE CASCADE,
