     2	import { dirname, join } from 'path';
     3	import { fileURLToPath } from 'url';
     4	import type pg from 'pg';
     5	
     6	const __filename = fileURLToPath(import.meta.url);
     7	const __dirname = dirname(__filename);
     8	
     9	const schemaPath = join(__dirname, 'schema.sql');
    10	const migrationsDir = join(__dirname, 'migrations');
    11	const createSchemaMigrationsTableSql = `
    12	  CREATE TABLE IF NOT EXISTS schema_migrations (
    13	    version TEXT PRIMARY KEY,
    14	    applied_at TIMESTAMPTZ DEFAULT now()
    15	  )
    16	`;
    17	
    18	type BootstrapLogger = Pick<Console, 'log' | 'error'>;
    19	type MigrationPool = Pick<pg.Pool, 'query' | 'connect'>;
    20	
    21	async function hasExistingSchema(pool: Pick<pg.Pool, 'query'>): Promise<boolean> {
    22	  const result = await pool.query(
    23	    `SELECT to_regclass('public.workspaces') IS NOT NULL AS has_schema`,
    24	  );
    25	  return result.rows[0]?.has_schema === true;
    26	}
    27	
    28	function isIgnorableSchemaError(error: unknown): boolean {
    29	  if (!(error instanceof Error) || !('code' in error)) {
    30	    return false;
    31	  }
    32	
    33	  if (error.code === '23505') {
    34	    const detail = 'detail' in error && typeof error.detail === 'string' ? error.detail : '';
    35	    return detail.includes('(extname)=(pg_trgm)');
    36	  }
    37	
    38	  return error.message.includes('already exists');
    39	}
    40	
    41	export async function ensureDatabaseSchema(
    42	  pool: MigrationPool,
    43	  logger?: BootstrapLogger,
    44	): Promise<string[]> {
    45	  if (!(await hasExistingSchema(pool))) {
    46	    const schema = readFileSync(schemaPath, 'utf-8');
    47	
    48	    try {
    49	      await pool.query(schema);
    50	    } catch (error) {
    51	      if (!isIgnorableSchemaError(error)) {
    52	        throw error;
    53	      }
    54	      logger?.log('Schema already present, continuing with pending migrations');
    55	    }
    56	  } else {
    57	    logger?.log('Existing schema detected, skipping full schema.sql replay');
    58	  }
    59	
    60	  await pool.query(createSchemaMigrationsTableSql);
    61	
    62	  const appliedResult = await pool.query('SELECT version FROM schema_migrations ORDER BY version');
    63	  const appliedMigrations = new Set(appliedResult.rows.map((row) => row.version as string));
    64	  const migrationFiles = existsSync(migrationsDir)
    65	    ? readdirSync(migrationsDir).filter((file) => file.endsWith('.sql')).sort()
    66	    : [];
    67	
    68	  const appliedNow: string[] = [];
    69	
    70	  for (const file of migrationFiles) {
    71	    const version = file.replace(/\.sql$/, '');
    72	    if (appliedMigrations.has(version)) {
    73	      continue;
    74	    }
    75	
    76	    const client = await pool.connect();
    77	    try {
    78	      await client.query('BEGIN');
    79	      await client.query('LOCK TABLE schema_migrations IN EXCLUSIVE MODE');
    80	      const lockedResult = await client.query('SELECT version FROM schema_migrations ORDER BY version');
    81	      const lockedApplied = new Set(lockedResult.rows.map((row) => row.version as string));
    82	      if (lockedApplied.has(version)) {
    83	        await client.query('ROLLBACK');
    84	        continue;
    85	      }
    86	      await client.query(readFileSync(join(migrationsDir, file), 'utf-8'));
    87	      await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
    88	      await client.query('COMMIT');
    89	      appliedNow.push(version);
    90	      logger?.log(`Applied migration ${version}`);
    91	    } catch (error) {
    92	      await client.query('ROLLBACK');
    93	      logger?.error(`Migration failed: ${version}`);
    94	      throw error;
    95	    } finally {
    96	      client.release();
    97	    }
    98	  }
    99	
   100	  return appliedNow;
   101	}
