CREATE OR REPLACE FUNCTION prevent_circular_parent()
RETURNS TRIGGER AS $$
DECLARE
  current_parent UUID;
  depth INT := 0;
  max_depth INT := 100;
BEGIN
  IF NEW.parent_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.parent_id IS NOT DISTINCT FROM NEW.parent_id THEN
    RETURN NEW;
  END IF;

  current_parent := NEW.parent_id;

  WHILE current_parent IS NOT NULL AND depth < max_depth LOOP
    IF current_parent = NEW.id THEN
      RAISE EXCEPTION 'Circular reference detected: document % cannot be a descendant of itself', NEW.id;
    END IF;

    SELECT parent_id INTO current_parent
    FROM documents
    WHERE id = current_parent;

    depth := depth + 1;
  END LOOP;

  IF depth >= max_depth THEN
    RAISE EXCEPTION 'Maximum nesting depth (%) exceeded while checking for circular reference', max_depth;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS prevent_circular_parent_trigger ON documents;
CREATE TRIGGER prevent_circular_parent_trigger
BEFORE INSERT OR UPDATE OF parent_id ON documents
FOR EACH ROW
EXECUTE FUNCTION prevent_circular_parent();

CREATE OR REPLACE FUNCTION assign_workspace_ticket_number()
RETURNS TRIGGER AS $$
DECLARE
  next_ticket INTEGER;
BEGIN
  IF NEW.ticket_number IS NOT NULL OR NEW.document_type NOT IN ('issue', 'project', 'program', 'wiki', 'person', 'sprint') THEN
    RETURN NEW;
  END IF;

  IF NEW.document_type = 'wiki' THEN
    RETURN NEW;
  END IF;

  IF NEW.document_type = 'person' THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(MAX(ticket_number), 0) + 1
    INTO next_ticket
  FROM documents
  WHERE workspace_id = NEW.workspace_id
    AND ticket_number IS NOT NULL;

  NEW.ticket_number := next_ticket;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS assign_workspace_ticket_number_trigger ON documents;
CREATE TRIGGER assign_workspace_ticket_number_trigger
BEFORE INSERT ON documents
FOR EACH ROW
EXECUTE FUNCTION assign_workspace_ticket_number();

CREATE OR REPLACE FUNCTION bump_workspace_document_update_timestamp()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS documents_updated_at_trigger ON documents;
CREATE TRIGGER documents_updated_at_trigger
BEFORE UPDATE ON documents
FOR EACH ROW
EXECUTE FUNCTION bump_workspace_document_update_timestamp();

