    18	type BootstrapLogger = Pick<Console, 'log' | 'error'>;
    19	type MigrationPool = Pick<pg.Pool, 'query' | 'connect'>;
    20	
    21	async function hasExistingSchema(pool: Pick<pg.Pool, 'query'>): Promise<boolean> {
    22	  const result = await pool.query(
    23	    `SELECT to_regclass('public.workspaces') IS NOT NULL AS has_schema`,
    24	  );
    25	  return result.rows[0]?.has_schema === true;
    26	}
    27	
    28	function isIgnorableSchemaError(error: unknown): boolean {
    29	  if (!(error instanceof Error) || !('code' in error)) {
    30	    return false;
    31	  }
    32	
    33	  if (error.code === '23505') {
    34	    const detail = 'detail' in error && typeof error.detail === 'string' ? error.detail : '';
    35	    return detail.includes('(extname)=(pg_trgm)');
    36	  }
    37	
    38	  return error.message.includes('already exists');
    39	}
    40	
    41	export async function ensureDatabaseSchema(
    42	  pool: MigrationPool,
    43	  logger?: BootstrapLogger,
    44	): Promise<string[]> {
    45	  if (!(await hasExistingSchema(pool))) {
    46	    const schema = readFileSync(schemaPath, 'utf-8');
    47	
    48	    try {
    49	      await pool.query(schema);
    50	    } catch (error) {
