#!/usr/bin/env npx ts-node
import { existsSync, readdirSync, readFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';
import { Pool } from 'pg';
import { loadProductionSecrets } from '../config/ssm.js';
import { loadEnvFiles } from '../config/env.js';
import { getDatabaseSslConfig } from './ssl.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const migrationsDir = join(__dirname, 'migrations');
const schemaMigrationsTableSql = `
  CREATE TABLE IF NOT EXISTS schema_migrations (
    version TEXT PRIMARY KEY,
    applied_at TIMESTAMPTZ DEFAULT now()
  )
`;

// Load local env files before reading DATABASE_URL
loadEnvFiles(join(__dirname, '../..'));

async function migrate() {
  await loadProductionSecrets();

  const databaseUrl = process.env.DATABASE_URL;
  if (!databaseUrl) {
    console.error('ERROR: DATABASE_URL environment variable is not set');
    process.exit(1);
  }

  const pool = new Pool({
    connectionString: databaseUrl,
    ssl: getDatabaseSslConfig(),
  });

  try {
    console.log('Running database migrations...');
    await pool.query(schemaMigrationsTableSql);

    const appliedResult = await pool.query('SELECT version FROM schema_migrations ORDER BY version');
    const appliedMigrations = new Set(appliedResult.rows.map((row) => row.version as string));

    const migrationFiles = existsSync(migrationsDir)
      ? readdirSync(migrationsDir).filter((file) => file.endsWith('.sql')).sort()
      : [];

    const appliedNow: string[] = [];

    for (const file of migrationFiles) {
      const version = file.replace(/\.sql$/, '');
      if (appliedMigrations.has(version)) {
        continue;
      }

      const sql = readFileSync(join(migrationsDir, file), 'utf-8');
      const client = await pool.connect();
      try {
        await client.query('BEGIN');
        await client.query(sql);
        await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
        await client.query('COMMIT');
        appliedNow.push(version);
        console.log(`Applied migration ${version}`);
      } catch (error) {
        await client.query('ROLLBACK');
        throw error;
      } finally {
        client.release();
      }
    }

    if (appliedNow.length === 0) {
      console.log('✅ All migrations already applied');
    } else {
      console.log(`✅ ${appliedNow.length} migration(s) applied successfully`);
    }
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    console.error('Database migration failed:', errorMessage);
    process.exit(1);
  } finally {
    await pool.end();
  }
}

migrate();

